from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import pandas as pd
import numpy as np
import tensorflow as tf
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Dense, Flatten, Conv2D, MaxPooling2D
from tensorflow.keras.utils import to_categorical
from tensorflow.keras.preprocessing.image import ImageDataGenerator
import os

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

def create_model(input_shape, num_classes):
    model = Sequential([
        Conv2D(32, (3, 3), activation='relu', input_shape=input_shape),
        MaxPooling2D((2, 2)),
        Flatten(),
        Dense(128, activation='relu'),
        Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam',
                  loss='categorical_crossentropy',
                  metrics=['accuracy'])
    return model

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'})
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'})
    filename = secure_filename(file.filename)
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    file.save(filepath)

    # Load csv and assume it contains image paths and corresponding labels
    data = pd.read_csv(filepath)
    image_paths = data['image_path'].values
    labels = to_categorical(data['label'].values)
    num_classes = labels.shape[1]

    # Load images
    images = []
    for path in image_paths:
        img = tf.keras.preprocessing.image.load_img(path, target_size=(64, 64))
        img_array = tf.keras.preprocessing.image.img_to_array(img)
        images.append(img_array)
    images = np.array(images)

    # Train model
    model = create_model(input_shape=images.shape[1:], num_classes=num_classes)
    datagen = ImageDataGenerator(validation_split=0.2)
    train_generator = datagen.flow(images, labels, subset='training')
    validation_generator = datagen.flow(images, labels, subset='validation')
    
    model.fit(train_generator, validation_data=validation_generator, epochs=10)

    return jsonify({'status': 'Training completed'})

if __name__ == '__main__':
    app.run(debug=True)